// Response handling utilities for AMFA steps
import { AdminResetUserPasswordCommand } from "@aws-sdk/client-cognito-identity-provider";
import { fetchCode } from "../fetchCode.mjs";
import { passwordlessLogin } from "../passwordlessLogin.mjs";
import { signUp } from "../signUp.mjs";
import { cookie2NamePrefix } from "../../const.mjs";
import { genSessionID } from "../genSessionID.mjs";
import { updateProfile } from "../updateProfile.mjs";
import {
  checkPasswordExpiration,
  createPWDHashHistory,
} from "../passwordhash.mjs";
import { getAsmSalt, getProviderId } from "../totp/getKms.mjs";
import { transUAttr, intersectOtpPolicies } from "./userManagement.mjs";
import { getPolicyName } from "./otpHandlers.mjs";
import { buildCookieName } from "./asmIntegration.mjs";
import { logger } from "./logger.mjs";

const cookieEnabledHeaders = {
  "Access-Control-Allow-Headers":
    "Content-Type,Authorization,X-Api-Key,Set-Cookie,Cookie,X-Requested-With",
  "Access-Control-Allow-Methods": "OPTIONS,GET,POST",
  "Access-Control-Expose-Headers": "Set-Cookie",
  "Access-Control-Allow-Credentials": "true",
};

// Enhanced response utility with better error handling
export const createResponse = (
  statusCode,
  body,
  headers,
  requestId,
  tenantId,
  domainName
) => {
  const responseHeaders = {
    ...headers,
    "Access-Control-Allow-Origin": `https://${tenantId}.idapersona.${domainName}`,
    requestId: requestId,
  };

  const response = {
    isBase64Encoded: false,
    statusCode,
    headers: responseHeaders,
    body: JSON.stringify({ message: body }),
  };

  logger.debug("Creating response", {
    statusCode,
    requestId,
    tenantId,
    bodyType: typeof body,
  });

  return response;
};

// Helper function to process ASM response
export const processASMResponse = async (
  amfaResponseJSON,
  step,
  event,
  realUsername,
  cognito,
  dynamodb,
  tableNames,
  appClientId,
  appSecret,
  magicString,
  amfaBrandings,
  amfaConfigs,
  amfaPolicies,
  userPoolId,
  tenantId,
  domainName,
  userAttributes,
  ug,
  headers,
  context
) => {
  const response = (statusCode, body, additionalHeaders = {}) => {
    return createResponse(
      statusCode,
      body,
      { ...headers, ...additionalHeaders },
      context.requestId,
      tenantId,
      domainName
    );
  };

  // Handle license check
  if (
    amfaResponseJSON.code === 202 &&
    amfaResponseJSON.platform !== "AWS" &&
    (step === "username" || step === "password")
  ) {
    logger.warn("Service not licensed", context);
    return response(
      501,
      "Your service is not yet licensed. Please contact aPersona."
    );
  }

  // Handle auto password reset on threat
  if (
    amfaConfigs.enable_auto_pwd_reset_on_threat === true &&
    (step === "username" || step === "password") &&
    (amfaResponseJSON.isUserUnderThreat === "true" ||
      amfaResponseJSON.isUserUnderThreat === true)
  ) {
    logger.warn("User under threat - resetting password", context);

    const params = {
      Username: event.email,
      UserPoolId: userPoolId,
    };

    await cognito.send(new AdminResetUserPasswordCommand(params));
    return response(402, "password reset due to account under threat");
  }

  // Process response codes
  switch (amfaResponseJSON.code) {
    case 200:
      return await handle200Response(
        amfaResponseJSON,
        step,
        event,
        realUsername,
        cognito,
        dynamodb,
        tableNames,
        appClientId,
        appSecret,
        magicString,
        amfaBrandings,
        amfaConfigs,
        userPoolId,
        tenantId,
        domainName,
        headers,
        context
      );

    case 202:
      return await handle202Response(
        amfaResponseJSON,
        step,
        event,
        cognito,
        dynamodb,
        tableNames,
        amfaConfigs,
        amfaPolicies,
        userAttributes,
        ug,
        tenantId,
        domainName,
        headers,
        context
      );

    case 203:
      logger.warn("Location not permitted", context);
      return response(
        203,
        "Your location is not permitted. Contact the help desk."
      );

    case 401:
      logger.warn("Authentication timeout or too many attempts", context);
      return response(
        401,
        "You took too long or entered your otp wrong too many times.\nTry your login again."
      );

    default:
      logger.warn("Unexpected ASM response code", {
        ...context,
        code: amfaResponseJSON.code,
      });
      return response(
        502,
        "We ran into an issue. Please contact the help desk."
      );
  }
};

// Helper function to handle 200 responses
export const handle200Response = async (
  amfaResponseJSON,
  step,
  event,
  realUsername,
  cognito,
  dynamodb,
  tableNames,
  appClientId,
  appSecret,
  magicString,
  amfaBrandings,
  amfaConfigs,
  userPoolId,
  tenantId,
  domainName,
  headers,
  context
) => {
  const response = (statusCode, body, additionalHeaders = {}) => {
    return createResponse(
      statusCode,
      body,
      { ...headers, ...additionalHeaders },
      context.requestId,
      tenantId,
      domainName
    );
  };

  if (amfaResponseJSON.message !== "OK") {
    if (amfaResponseJSON.message?.includes("Exceeds Allowed Users")) {
      logger.warn("License user limit exceeded", context);
      return response(
        501,
        "Your account has not been licensed for access. Please contact the help desk."
      );
    }
    logger.warn("ASM returned 200 but not OK", {
      ...context,
      message: amfaResponseJSON.message,
    });
    return response(
      501,
      "The login service is not currently available. Contact the help desk."
    );
  }

  switch (step) {
    case "updateProfile":
      await updateProfile(
        event.email,
        event.otptype,
        event.otpaddr,
        amfaBrandings.email_logo_url,
        amfaBrandings.service_name,
        cognito,
        userPoolId
      );
      logger.info("Profile updated successfully", context);
      return response(200, "OK");

    case "username":
    case "password":
    case "verifyotp":
    case "pwdreset2":
    case "pwdreset3":
    case "selfservice2":
    case "selfservice3":
    case "updateProfileSendOTP":
    case "emailverificationSendOTP":
      const url =
        step === "username"
          ? await passwordlessLogin(
              realUsername,
              event,
              cognito,
              dynamodb,
              tableNames,
              appClientId,
              appSecret,
              magicString
            )
          : await fetchCode(event.email, event.apti, tableNames);

      if (url) {
        const date = new Date();
        date.setDate(date.getDate() + 120);

        const amfaCookieName = buildCookieName(
          event.email,
          getPolicyName(step, {}, "default"),
          event.origin,
          await getAsmSalt(tenantId)
        );
        const cookieValue = `${amfaCookieName}=${
          amfaResponseJSON.identifier
        }; Domain=${tenantId}.idapersona.${domainName}; HttpOnly; Expires=${date.toUTCString()}; Secure; SameSite=Strict; Path=/`;
        const cookie2Value = `${cookie2NamePrefix}=${amfaResponseJSON.identifier.substr(
          -16,
          16
        )}; Domain=${tenantId}.idapersona.${domainName}; Expires=${date.toUTCString()}; Secure; SameSite=Strict; Path=/`;

        logger.info("Authentication successful, setting cookies", {
          ...context,
          url,
        });

        return {
          statusCode: 200,
          isBase64Encoded: false,
          multiValueHeaders: {
            "Set-Cookie": [cookieValue, cookie2Value],
          },
          headers: {
            ...cookieEnabledHeaders,
            "Access-Control-Allow-Origin": `https://${tenantId}.idapersona.${domainName}`,
          },
          body: JSON.stringify({ location: url }),
        };
      } else {
        logger.error(
          "Failed to generate URL for successful authentication",
          context
        );
        return response(505, "Service error, please contact the help desk.");
      }

    case "pwdresetverify2":
    case "pwdresetverify3":
    case "selfserviceverify2":
    case "selfserviceverify3":
      const apti = step.startsWith("selfserviceverify")
        ? "updateprofile"
        : event.apti;
      const uuid = await genSessionID(
        event.email,
        apti,
        null,
        dynamodb,
        tableNames
      );
      logger.info("Verification successful, session created", {
        ...context,
        uuid,
      });

      return {
        isBase64Encoded: false,
        statusCode: 200,
        headers: { ...headers, requestId: context.requestId },
        body: JSON.stringify({ message: "OK", uuid }),
      };

    case "emailverificationverifyotp":
      const user = await signUp(
        event.email,
        event.password,
        event.attributes,
        cognito,
        dynamodb,
        tableNames,
        tenantId,
        userPoolId
      );
      if (user?.User) {
        const sessionUuid = await genSessionID(
          event.email,
          event.apti,
          null,
          dynamodb,
          tableNames
        );
        await createPWDHashHistory(
          event.email,
          event.password,
          dynamodb,
          amfaConfigs,
          tableNames,
          tenantId
        );
        logger.info("Email verification and signup successful", {
          ...context,
          userId: user.User.Username,
        });

        return {
          isBase64Encoded: false,
          statusCode: 200,
          headers: { ...headers, requestId: context.requestId },
          body: JSON.stringify({ message: "OK", uuid: sessionUuid }),
        };
      }
      logger.error("Signup failed after email verification", context);
      return response(
        501,
        "The login service is not currently available. Contact the help desk."
      );

    default:
      logger.warn("Unexpected step in 200 response handler", {
        ...context,
        step,
      });
      return response(
        505,
        "The login service is not currently available. Contact the help desk."
      );
  }
};

// Helper function to handle 202 responses
export const handle202Response = async (
  amfaResponseJSON,
  step,
  event,
  cognito,
  dynamodb,
  tableNames,
  amfaConfigs,
  amfaPolicies,
  userAttributes,
  ug,
  tenantId,
  domainName,
  headers,
  context
) => {
  const response = (statusCode, body, additionalHeaders = {}) => {
    return createResponse(
      statusCode,
      body,
      { ...headers, ...additionalHeaders },
      context.requestId,
      tenantId,
      domainName
    );
  };

  switch (step) {
    case "username":
      logger.info("Username phase requires password", context);
      return response(202, "Your identity requires password login.");

    case "password":
      const isPasswordExpired = await checkPasswordExpiration(
        event.email,
        dynamodb,
        amfaConfigs,
        tableNames,
        tenantId
      );
      if (isPasswordExpired) {
        logger.warn("Password expired", context);
        return response(401, "PASSWORD_EXPIRED");
      }

      const otpOptions = intersectOtpPolicies(
        amfaPolicies[ug].permissions,
        amfaConfigs.master_additional_otp_methods
      );

      const provider_id = await getProviderId(tenantId);
      const otpData = await transUAttr(
        event.email,
        userAttributes,
        otpOptions,
        provider_id,
        dynamodb,
        tableNames.totpTokenTable
      );

      let OTPMethodsCount = 0;
      if (otpOptions) {
        otpOptions.forEach((option) => {
          switch (option) {
            case "e":
              if (otpData.email) OTPMethodsCount++;
              break;
            case "ae":
              if (otpData.aemail) OTPMethodsCount++;
              break;
            case "s":
              if (otpData.phoneNumber) OTPMethodsCount++;
              break;
            case "v":
              if (
                otpData.vPhoneNumber &&
                otpData.vPhoneNumber !== otpData.phoneNumber
              )
                OTPMethodsCount++;
              break;
            case "t":
              if (otpData.mobileToken) OTPMethodsCount++;
              break;
            default:
              break;
          }
        });
      }

      let uuid = null;
      if (OTPMethodsCount === 0) {
        uuid = await genSessionID(
          event.email,
          event.apti,
          "nonemfa",
          dynamodb,
          tableNames
        );
      }

      logger.info("Password phase requires OTP challenge", {
        ...context,
        otpMethodsCount: OTPMethodsCount,
      });

      return {
        statusCode: 202,
        isBase64Encoded: false,
        headers: {
          ...cookieEnabledHeaders,
          "Access-Control-Allow-Origin": `https://${tenantId}.idapersona.${domainName}`,
          requestId: context.requestId,
        },
        body: JSON.stringify({
          email: event.email,
          ...otpData,
          otpOptions,
          uuid,
        }),
      };

    case "sendotp":
    case "pwdreset2":
    case "pwdreset3":
    case "selfservice2":
    case "selfservice3":
    case "emailverificationSendOTP":
      logger.info("OTP sent successfully", {
        ...context,
        otpType: event.otptype,
      });
      return response(
        202,
        event.otptype === "t" ? "Input Mobile TOTP" : amfaResponseJSON.message
      );

    case "updateProfileSendOTP":
      const profileUuid = await genSessionID(
        event.email,
        event.apti,
        event.otpaddr,
        dynamodb,
        tableNames
      );
      logger.info("Profile update OTP sent", { ...context, uuid: profileUuid });

      return {
        isBase64Encoded: false,
        statusCode: 202,
        headers: { ...headers, requestId: context.requestId },
        body: JSON.stringify({
          message: amfaResponseJSON.message,
          uuid: profileUuid,
        }),
      };

    case "verifyotp":
    case "pwdresetverify2":
    case "pwdresetverify3":
    case "selfserviceverify2":
    case "selfserviceverify3":
    case "updateProfile":
    case "emailverificationverifyotp":
      logger.warn("OTP verification failed", context);
      return response(
        403,
        "The identity code you entered was not correct. Please try again."
      );

    default:
      logger.warn("Unexpected step in 202 response handler", {
        ...context,
        step,
      });
      return response(202, amfaResponseJSON.message || "Unexpected response");
  }
};
