// OTP handling utilities for AMFA steps
import { updateProfile } from "../updateProfile.mjs";
import { getProviderId } from "../totp/getKms.mjs";
import { transUAttr } from "./userManagement.mjs";
import { logger } from "./logger.mjs";

// Helper function to validate profile updates
export const validateProfileUpdate = (event, userAttributes) => {
  if (event.profile !== "" && event.otpaddr !== event.profile?.toLowerCase()) {
    return { error: "Your entry was not valid, please try again." };
  }

  if (event.otptype === "ae") {
    if (
      event.newProfile?.toLowerCase().trim() ===
      event.email.toLowerCase().trim()
    ) {
      return { error: "Your alt-email can't be same as your account email." };
    }
  }

  return { error: null };
};

// Helper function to handle profile removal
export const handleProfileRemoval = async (
  event,
  userAttributes,
  amfaBrandings,
  cognito,
  userPoolId,
  context
) => {
  let equalCurrentProfile = false;

  switch (event.otptype) {
    case "ae":
      equalCurrentProfile =
        userAttributes["custom:alter-email"] === event.profile;
      break;
    case "s":
      equalCurrentProfile = event.profile === userAttributes.phone_number;
      break;
    case "v":
      equalCurrentProfile =
        event.profile === userAttributes["custom:voice-number"];
      break;
    default:
      break;
  }

  if (!equalCurrentProfile) {
    logger.warn("Profile removal validation failed", {
      ...context,
      otptype: event.otptype,
    });
    return {
      statusCode: 400,
      isBase64Encoded: false,
      headers: {
        "Access-Control-Allow-Origin": `https://${context.tenantId}.idapersona.${context.domainName}`,
        requestId: context.requestId,
      },
      body: JSON.stringify({
        message: "Your entry was not valid, please try again.",
      }),
    };
  }

  await updateProfile(
    event.email,
    event.otptype,
    "",
    amfaBrandings.email_logo_url,
    amfaBrandings.service_name,
    cognito,
    userPoolId
  );

  logger.info("Profile removed successfully", context);
  return {
    statusCode: 200,
    isBase64Encoded: false,
    headers: {
      "Access-Control-Allow-Origin": `https://${context.tenantId}.idapersona.${context.domainName}`,
      requestId: context.requestId,
    },
    body: JSON.stringify({ message: "OK" }),
  };
};

// Helper function to handle OTP options
export const handleOTPOptions = async (
  step,
  event,
  userAttributes,
  amfaConfigs,
  dynamodb,
  tableNames,
  headers,
  context
) => {
  let otpOptions = amfaConfigs.master_additional_otp_methods;
  const provider_id = await getProviderId(context.tenantId);

  const otpData = await transUAttr(
    event.email,
    userAttributes,
    otpOptions,
    provider_id,
    dynamodb,
    tableNames.totpTokenTable
  );

  if (
    (!otpOptions || !otpOptions.includes("e")) &&
    step === "getUserOtpOptions"
  ) {
    otpOptions = otpOptions ? ["e"].concat(otpOptions) : ["e"];
  }

  const body = JSON.stringify({
    otpOptions,
    email: userAttributes.email,
    given_name: userAttributes.given_name,
    family_name: userAttributes.family_name,
    ...otpData,
  });

  logger.debug("OTP options response prepared", {
    ...context,
    step,
    optionsCount: otpOptions?.length || 0,
  });

  return {
    statusCode: 200,
    isBase64Encoded: false,
    headers,
    body,
  };
};

// Helper function to get policy name
export const getPolicyName = (step, amfaPolicies, ug) => {
  if (step.startsWith("pwdreset")) {
    return amfaPolicies["pwd-reset"]?.policy_name;
  }
  if (step.startsWith("selfservice") || step.startsWith("updateProfile")) {
    return amfaPolicies["self-service"]?.policy_name;
  }
  if (step.startsWith("emailverification")) {
    return amfaPolicies["user-registration"]?.policy_name;
  }
  return amfaPolicies[ug]?.policy_name;
};
