/**
 * Configuration caching utility for AMFA lambda functions
 * Implements in-memory caching with TTL to reduce DynamoDB calls
 */

// In-memory cache with TTL
const cache = new Map();
const CACHE_TTL = 5 * 60 * 1000; // 5 minutes in milliseconds

/**
 * Cache entry structure
 */
class CacheEntry {
  constructor(data) {
    this.data = data;
    this.timestamp = Date.now();
  }

  isExpired() {
    return Date.now() - this.timestamp > CACHE_TTL;
  }
}

/**
 * Generate cache key for tenant-specific config
 */
const getCacheKey = (configType, tenantId) => {
  return `${configType}:${tenantId}`;
};

/**
 * Get configuration from cache or fetch from DynamoDB
 */
export const getCachedConfig = async (
  configType,
  dynamodb,
  tableNames,
  tenantId,
  fetchConfigFn
) => {
  const cacheKey = getCacheKey(configType, tenantId);
  const cachedEntry = cache.get(cacheKey);

  // Return cached data if valid
  if (cachedEntry && !cachedEntry.isExpired()) {
    console.log(`[Tenant: ${tenantId}] Cache hit for ${configType}`);
    return cachedEntry.data;
  }

  // Fetch from DynamoDB and cache
  try {
    console.log(
      `[Tenant: ${tenantId}] Cache miss for ${configType}, fetching from DynamoDB`
    );
    const data = await fetchConfigFn(
      configType,
      dynamodb,
      tableNames,
      tenantId
    );

    // Store in cache
    cache.set(cacheKey, new CacheEntry(data));

    return data;
  } catch (error) {
    console.error(
      `[Tenant: ${tenantId}] Failed to fetch ${configType}:`,
      error
    );
    throw error;
  }
};

/**
 * Batch fetch multiple configurations with parallel execution
 */
export const batchFetchConfigs = async (
  configTypes,
  dynamodb,
  tableNames,
  tenantId,
  fetchConfigFn
) => {
  const promises = configTypes.map((configType) =>
    getCachedConfig(configType, dynamodb, tableNames, tenantId, fetchConfigFn)
  );

  try {
    const results = await Promise.all(promises);

    // Return as object with config type as key
    const configObject = {};
    configTypes.forEach((configType, index) => {
      configObject[configType] = results[index];
    });

    return configObject;
  } catch (error) {
    console.error(`[Tenant: ${tenantId}] Batch config fetch failed:`, error);
    throw error;
  }
};

/**
 * Clear cache for specific tenant (useful for testing or config updates)
 */
export const clearTenantCache = (tenantId) => {
  const keysToDelete = [];

  for (const [key] of cache) {
    if (key.endsWith(`:${tenantId}`)) {
      keysToDelete.push(key);
    }
  }

  keysToDelete.forEach((key) => cache.delete(key));
  console.log(
    `[Tenant: ${tenantId}] Cleared ${keysToDelete.length} cache entries`
  );
};

/**
 * Clear all cache entries (useful for memory management)
 */
export const clearAllCache = () => {
  const size = cache.size;
  cache.clear();
  console.log(`Cleared all cache entries (${size} entries)`);
};

/**
 * Get cache statistics
 */
export const getCacheStats = () => {
  const now = Date.now();
  let validEntries = 0;
  let expiredEntries = 0;

  for (const [, entry] of cache) {
    if (entry.isExpired()) {
      expiredEntries++;
    } else {
      validEntries++;
    }
  }

  return {
    totalEntries: cache.size,
    validEntries,
    expiredEntries,
    cacheHitRate: validEntries / (validEntries + expiredEntries) || 0,
  };
};
