import {
	SecretsManagerClient,
	GetSecretValueCommand,
	UpdateSecretCommand,
} from "@aws-sdk/client-secrets-manager";

const client = new SecretsManagerClient({
	region: process.env.AWS_REGION,
});

/**
 * Get secret name for a tenant.
 * Convention: apersona/{tenantId}/secret
 */
const getSecretName = (tenantId) => `apersona/${tenantId}/secret`;

/**
 * Get SMTP secret name for a tenant.
 * Convention: apersona/{tenantId}/smtp
 */
const getSMTPSecretName = (tenantId) => `apersona/${tenantId}/smtp`;

export const setSMTP = async (tenantId, smtp) => {
	const secretId = getSMTPSecretName(tenantId);
	const response = await client.send(
		new UpdateSecretCommand({
			SecretId: secretId,
			SecretString: JSON.stringify(smtp),
		})
	);
	return response;
}

export const getSecret = async (tenantId) => {
	const secretId = getSecretName(tenantId);
	const response = await client.send(
		new GetSecretValueCommand({
			SecretId: secretId,
		})
	);
	const secret = JSON.parse(response.SecretString);
	return secret;
}

export const getAsmSalt = async (tenantId) => {
	try {
		const secret = await getSecret(tenantId);
		return secret?.asmSalt;
	}
	catch (e) {
		console.error('get asm salt failed with:', e);
		return null;
	}
}

export const getProviderId = async (tenantId) => {
	try {
		const secret = await getSecret(tenantId);
		return secret?.Provider_Id;
	}
	catch (e) {
		console.error('get provider id failed with:', e);
		return null;
	}
}

export const getSMTP = async (tenantId) => {
	const secretId = getSMTPSecretName(tenantId);
	console.log('get smtp secret', secretId);
	const response = await client.send(
		new GetSecretValueCommand({
			SecretId: secretId,
		})
	);

	const secret = JSON.parse(response.SecretString);
	secret.secure = secret.secure === 'true' || secret.secure === true ? true : false
	console.log('get smtp secret response', secret);

	return secret;
}