// Modular version of amfaSteps with separated concerns and improved maintainability
import { checkSessionId } from "./checkSessionId.mjs";
import { getAsmSalt } from "./totp/getKms.mjs";

// Import modular components
import { logger } from "./amfaSteps/logger.mjs";
import {
  clearUserCache,
  getUserInfo,
  getUserGroup,
  validateOTPAddress,
  setOTPAddress,
} from "./amfaSteps/userManagement.mjs";
import {
  validateProfileUpdate,
  handleProfileRemoval,
  handleOTPOptions,
  getPolicyName,
} from "./amfaSteps/otpHandlers.mjs";
import { executeASMAuthentication } from "./amfaSteps/asmIntegration.mjs";
import {
  createResponse,
  processASMResponse,
} from "./amfaSteps/responseHandlers.mjs";

export const amfaSteps = async (
  event,
  headers,
  cognito,
  step,
  amfaBrandings,
  amfaPolicies,
  amfaConfigs,
  dynamodb,
  tableNames,
  tenantId,
  userPoolId,
  domainName,
  appClientId,
  appSecret,
  magicString,
) => {
  const startTime = Date.now();
  const context = {
    step,
    email: event.email,
    tenantId,
    requestId: event.requestId,
    domainName,
  };

  logger.info("amfaSteps execution started", context);

  // Clear execution cache at the start of each request
  clearUserCache();

  const response = (statusCode, body) =>
    createResponse(
      statusCode,
      body,
      headers,
      event.requestId,
      tenantId,
      domainName,
    );

  try {
    // Handle session validation steps
    if (
      [
        "updateProfile",
        "removeProfile",
        "checkSessionId",
        "updateProfileSendOTP",
      ].includes(step)
    ) {
      const isValidUuid = await checkSessionId(
        event,
        step,
        dynamodb,
        tableNames,
        tenantId,
      );
      if (!isValidUuid) {
        logger.warn("Invalid session ID", { ...context, step });
        return response(400, "Invalid UUID");
      }

      if (step === "checkSessionId") {
        logger.info("Session ID validated successfully", context);
        return response(200, "valid Session ID");
      }
    }

    // Get cached salt and ASM URL
    const [salt, asmurl] = await Promise.all([
      getAsmSalt(tenantId),
      Promise.resolve(amfaConfigs.asmurl),
    ]);

    let user = null;
    let userAttributes = null;
    let ug = "default";

    // Master OTP methods control check
    const otp_steps_under_master_control_config = [
      "sendotp",
      "verifyotp",
      "pwdreset2",
      "pwdreset3",
      "pwdresetverify2",
      "pwdresetverify3",
      "selfservice2",
      "selfservice3",
      "selfserviceverify2",
      "selfserviceverify3",
      "updateProfileSendOTP",
      "updateProfile",
      "removeProfile",
    ];

    if (
      amfaConfigs.master_additional_otp_methods &&
      !amfaConfigs.master_additional_otp_methods.includes(event.otptype) &&
      otp_steps_under_master_control_config.includes(step) &&
      event.otptype !== "e"
    ) {
      logger.warn("Master OTP methods restriction violated", {
        ...context,
        otptype: event.otptype,
        allowedMethods: amfaConfigs.master_additional_otp_methods,
      });
      return response(403, "Master OTP methods restriction");
    }

    let realUsername = event.email;

    // Skip user lookup for email verification steps
    if (
      !["emailverificationSendOTP", "emailverificationverifyotp"].includes(step)
    ) {
      const userInfo = await getUserInfo(
        event.email,
        cognito,
        userPoolId,
        tenantId,
      );

      if (userInfo.error) {
        logger.warn("User lookup failed", {
          ...context,
          error: userInfo.error,
        });

        // For forgot password / OTP options: return fake email-only response
        // to prevent username enumeration
        if (["getOtpOptions", "getUserOtpOptions"].includes(step)) {
          logger.info("User not found during OTP options - returning safe response to prevent enumeration", context);
          return response(200, JSON.stringify({
            otpOptions: ["e"],
            email: event.email,
          }));
        }

        return response(
          500,
          userInfo.error.includes("not found")
            ? "Did not find valid user for this email"
            : "Did not find valid user for this email, or user account has not been activated",
        );
      }

      user = userInfo.user;
      userAttributes = userInfo.userAttributes;
      realUsername = user.Username;

      // Handle force password change
      if (
        step === "username" &&
        ["FORCE_CHANGE_PASSWORD", "RESET_REQUIRED"].includes(user.UserStatus)
      ) {
        logger.info("User requires password change", {
          ...context,
          userStatus: user.UserStatus,
        });
        return response(202, user.UserStatus);
      }

      // Handle OTP address confirmation
      if (step === "confirmOTPAddress") {
        const isValidAddress = await validateOTPAddress(
          event,
          userAttributes,
          context,
        );
        return response(
          isValidAddress ? 200 : 202,
          isValidAddress ? "Valid" : "Invalid",
        );
      }

      // Get user group with caching
      ug = await getUserGroup(
        realUsername,
        cognito,
        userPoolId,
        amfaPolicies,
        tenantId,
      );
      logger.debug("User group determined", { ...context, userGroup: ug });
    }

    // Check passwordless policy
    if (step === "username" && !amfaPolicies[ug]?.enable_passwordless) {
      logger.info("Passwordless disabled for user group", {
        ...context,
        userGroup: ug,
      });
      return response(202, "Your identity requires password login.");
    }

    // Set OTP address based on type
    await setOTPAddress(event, userAttributes);

    // Handle profile update validation
    if (step === "updateProfileSendOTP") {
      const profileValidation = validateProfileUpdate(event, userAttributes);
      if (profileValidation.error) {
        logger.warn("Profile update validation failed", {
          ...context,
          error: profileValidation.error,
        });
        return response(400, profileValidation.error);
      }
    }

    // Handle profile removal
    if (step === "removeProfile") {
      const removalResult = await handleProfileRemoval(
        event,
        userAttributes,
        amfaBrandings,
        cognito,
        userPoolId,
        context,
      );
      if (removalResult) return removalResult;
    }

    // Handle OTP options requests
    if (["getOtpOptions", "getUserOtpOptions"].includes(step)) {
      return await handleOTPOptions(
        step,
        event,
        userAttributes,
        amfaConfigs,
        dynamodb,
        tableNames,
        headers,
        context,
      );
    }

    // Get policy name for ASM
    const policyName = getPolicyName(step, amfaPolicies, ug);
    if (!policyName) {
      logger.error("No valid ASM policy found", { ...context, userGroup: ug });
      return response(
        500,
        `Did not find a valid ASM Policy for the user group: ${ug}`,
      );
    }

    // Build ASM URL and execute authentication
    const asmResponse = await executeASMAuthentication(
      event,
      step,
      asmurl,
      policyName,
      salt,
      tenantId,
      domainName,
      amfaConfigs,
      context,
      dynamodb,
    );

    if (!asmResponse) {
      logger.error("ASM response failed", context);
      return response(503, "amfa response error");
    }

    // Process ASM response
    const finalResponse = await processASMResponse(
      asmResponse,
      step,
      event,
      realUsername,
      cognito,
      dynamodb,
      tableNames,
      appClientId,
      appSecret,
      magicString,
      amfaBrandings,
      amfaConfigs,
      amfaPolicies,
      userPoolId,
      tenantId,
      domainName,
      userAttributes,
      ug,
      headers,
      context,
    );

    const duration = Date.now() - startTime;
    logger.info("amfaSteps execution completed", {
      ...context,
      duration,
      statusCode: finalResponse.statusCode,
    });

    return finalResponse;
  } catch (error) {
    const duration = Date.now() - startTime;
    logger.error("amfaSteps execution failed", error, { ...context, duration });

    if (error.message?.indexOf("fetch failed") !== -1) {
      return response(
        504,
        "MFA Service is not responding. Contact the help desk.",
      );
    } else {
      return response(504, error.message || "Unknown error in amfa steps");
    }
  }
};
