import {
  CognitoIdentityProviderClient,
  ListUsersCommand,
} from "@aws-sdk/client-cognito-identity-provider";
import { DynamoDBClient } from "@aws-sdk/client-dynamodb";

import { amfaSteps } from "./utils/amfaSteps.mjs";
import { fetchConfig } from "./utils/fetchConfig.mjs";
import { getCachedConfig } from "./utils/configCache.mjs";
import { checkSessionId } from "./utils/checkSessionId.mjs";
import { deleteTotp, registotp } from "./utils/totp/registOtp.mjs";
import { asmDeleteUser } from "./utils/asmDeleteUser.mjs";
import { notifyProfileChange } from "./utils/mailer.mjs";
import { deletePwdHashByUser } from "./utils/passwordhash.mjs";
import { getHeaders, responseWithRequestId } from "./utils/amfaUtils.mjs";
import { adminGetSecrets, adminSetSmtp } from "./utils/admingetsecrets.mjs";
import {
  validateEmail,
  validateTOTP,
  validateOTP,
  validatePhoneNumber,
} from "./utils/inputValidate.mjs";
import { getProviderId } from "./utils/totp/getKms.mjs";
import { getTenantContext, createResponse } from "tenant-utils";

// Initialize AWS clients with optimized configuration
const dynamodb = new DynamoDBClient({
  region: process.env.AWS_REGION,
  maxAttempts: 3,
  retryMode: "adaptive",
});

const client = new CognitoIdentityProviderClient({
  region: process.env.AWS_REGION,
  maxAttempts: 3,
  retryMode: "adaptive",
});

const C_OTP_TYPES = ["e", "ae", "s", "v", "t"];

// Enhanced logging utility
const logger = {
  info: (message, context = {}) => {
    console.log(
      JSON.stringify({
        level: "INFO",
        timestamp: new Date().toISOString(),
        message,
        ...context,
      }),
    );
  },
  warn: (message, context = {}) => {
    console.warn(
      JSON.stringify({
        level: "WARN",
        timestamp: new Date().toISOString(),
        message,
        ...context,
      }),
    );
  },
  error: (message, error = null, context = {}) => {
    console.error(
      JSON.stringify({
        level: "ERROR",
        timestamp: new Date().toISOString(),
        message,
        error: error
          ? {
              name: error.name,
              message: error.message,
              stack: error.stack,
            }
          : null,
        ...context,
      }),
    );
  },
  debug: (message, context = {}) => {
    if (process.env.LOG_LEVEL === "DEBUG") {
      console.log(
        JSON.stringify({
          level: "DEBUG",
          timestamp: new Date().toISOString(),
          message,
          ...context,
        }),
      );
    }
  },
};

// Enhanced input validation with detailed error reporting
const validateInputParams = (payload) => {
  const context = { phase: payload.phase, email: payload.email };

  try {
    if (
      payload.phase === "admingetsecretinfo" ||
      payload.phase === "adminupdatesmtp"
    ) {
      const isValid = Boolean(payload.tenantid);
      if (!isValid) {
        logger.warn("Validation failed: missing tenantid", context);
      }
      return isValid;
    }

    if (!payload.email || validateEmail(payload.email)) {
      logger.warn("Validation failed: invalid email", context);
      return false;
    }

    // Enhanced validation with specific error logging
    switch (payload.phase) {
      case "adminchecklicense":
        return Boolean(payload.email);

      case "admindeletetotp":
      case "admindeleteuser":
      case "adminupdateuser":
        return Boolean(payload.email);

      case "username":
        const usernameValid = Boolean(
          payload.email && payload.apti && payload.authParam,
        );
        if (!usernameValid) {
          logger.warn("Username validation failed", {
            ...context,
            hasEmail: Boolean(payload.email),
            hasApti: Boolean(payload.apti),
            hasAuthParam: Boolean(payload.authParam),
          });
        }
        return usernameValid;

      case "password":
        const passwordValid = Boolean(
          payload.email &&
          payload.password &&
          payload.apti &&
          payload.authParam,
        );
        if (!passwordValid) {
          logger.warn("Password validation failed", {
            ...context,
            hasEmail: Boolean(payload.email),
            hasPassword: Boolean(payload.password),
            hasApti: Boolean(payload.apti),
            hasAuthParam: Boolean(payload.authParam),
          });
        }
        return passwordValid;

      case "sendotp":
      case "pwdreset2":
      case "pwdreset3":
      case "selfservice2":
      case "selfservice3":
      case "updateProfileSendOTP":
      case "emailverificationSendOTP":
        const otpSendValid = Boolean(
          payload.email && payload.otptype && payload.apti && payload.authParam,
        );
        if (!otpSendValid) {
          logger.warn("OTP send validation failed", {
            ...context,
            hasEmail: Boolean(payload.email),
            hasOtptype: Boolean(payload.otptype),
            hasApti: Boolean(payload.apti),
            hasAuthParam: Boolean(payload.authParam),
          });
        }
        return otpSendValid;

      case "verifyotp":
      case "pwdresetverify2":
      case "pwdresetverify3":
      case "selfserviceverify2":
      case "selfserviceverify3":
        if (!C_OTP_TYPES.includes(payload.otptype)) {
          logger.warn("Invalid OTP type", {
            ...context,
            otptype: payload.otptype,
          });
          return false;
        }
        if (payload.otptype === "t" && validateTOTP(payload.otpcode)) {
          logger.warn("Invalid TOTP code format", context);
          return false;
        }
        if (payload.otptype !== "t" && validateOTP(payload.otpcode)) {
          logger.warn("Invalid OTP code format", context);
          return false;
        }
        return Boolean(
          payload.email &&
          payload.otpcode &&
          payload.otptype &&
          payload.apti &&
          payload.authParam,
        );

      case "emailverificationverifyotp":
        if (!C_OTP_TYPES.includes(payload.otptype)) return false;
        if (payload.otptype === "t" && validateTOTP(payload.otpcode))
          return false;
        if (payload.otptype !== "t" && validateOTP(payload.otpcode))
          return false;
        return Boolean(
          payload.email &&
          payload.otpcode &&
          payload.otptype &&
          payload.apti &&
          payload.authParam &&
          payload.attributes &&
          payload.password,
        );

      case "updateProfile":
        if (!payload.otptype || !C_OTP_TYPES.includes(payload.otptype))
          return false;
        if (payload.otptype === "t" && validateTOTP(payload.otpcode))
          return false;
        if (payload.otptype !== "t" && validateOTP(payload.otpcode))
          return false;
        if (payload.otptype === "ae" && validateEmail(payload.newProfile))
          return false;
        if (
          (payload.otptype === "s" || payload.otptype === "v") &&
          validatePhoneNumber(payload.newProfile)
        )
          return false;
        return Boolean(
          payload.email &&
          payload.otpcode &&
          payload.otptype &&
          payload.apti &&
          payload.authParam &&
          payload.uuid,
        );

      case "getOtpOptions":
      case "getUserOtpOptions":
        return Boolean(payload.email && payload.authParam);

      case "removeProfile":
        return Boolean(
          payload.email &&
          payload.authParam &&
          payload.profile &&
          payload.otptype &&
          C_OTP_TYPES.includes(payload.otptype),
        );

      case "registotp":
        return Boolean(
          payload.email &&
          payload.uuid &&
          payload.secretCode &&
          payload.secretCode.length === 16 &&
          !validateTOTP(payload.sixDigits) &&
          payload.tokenLabel &&
          payload.tokenLabel.length <= 25,
        );

      case "confirmOTPAddress":
        return Boolean(
          payload.email &&
          payload.authParam &&
          payload.otpaddr &&
          payload.otptype &&
          C_OTP_TYPES.includes(payload.otptype),
        );

      default:
        logger.warn("Unknown phase in validation", { phase: payload.phase });
        return false;
    }
  } catch (error) {
    logger.error("Error during input validation", error, context);
    return false;
  }
};

const getIPFromHeader = (fwdfor) => {
  try {
    if (!fwdfor) return "0.0.0.0";
    const IPs = fwdfor.split(",");
    return IPs[0].trim();
  } catch (error) {
    logger.warn("Error parsing IP from header", { fwdfor });
    return "0.0.0.0";
  }
};

// Enhanced error response utility
const createErrorResponse = (
  statusCode,
  message,
  requestId,
  tenantId = null,
  domainName = null,
) => {
  const context = { statusCode, message, requestId, tenantId };
  logger.error("Creating error response", null, context);

  return responseWithRequestId(statusCode, message, requestId, tenantId, domainName);
};

// Main lambda handler with comprehensive optimization
export const handler = async (event) => {
  const startTime = Date.now();
  const requestId =
    Math.random().toString(36).substring(2, 16) +
    Math.random().toString(36).substring(2, 16);

  logger.info("Lambda invocation started", {
    requestId,
    httpMethod: event.httpMethod,
    path: event.path,
  });

  let tenantContext = null;

  try {
    // Extract tenant context from request
    tenantContext = await getTenantContext(event);
    logger.info("Tenant context extracted", {
      requestId,
      tenantId: tenantContext.tenantId,
      domainName: tenantContext.domainName,
    });

    // Parse and validate payload
    let payload;
    try {
      payload = JSON.parse(event.body);
    } catch (parseError) {
      logger.error("Failed to parse request body", parseError, { requestId });
      return createErrorResponse(
        400,
        "Invalid JSON in request body",
        requestId,
        tenantContext?.tenantId,
        tenantContext?.domainName,
      );
    }

    logger.debug("Payload parsed", {
      requestId,
      tenantId: tenantContext.tenantId,
      phase: payload.phase,
      email: payload.email,
    });

    // Validate input parameters
    if (!payload || !validateInputParams(payload)) {
      logger.warn("Input validation failed", {
        requestId,
        tenantId: tenantContext.tenantId,
        phase: payload?.phase,
      });
      return createErrorResponse(
        422,
        "Invalid input parameters",
        requestId,
        tenantContext.tenantId,
        tenantContext.domainName,
      );
    }

    // Fetch configurations with caching
    const configPromises = [
      getCachedConfig(
        "amfaBrandings",
        dynamodb,
        tenantContext.tableNames,
        tenantContext.tenantId,
        fetchConfig,
      ),
      getCachedConfig(
        "amfaPolicies",
        dynamodb,
        tenantContext.tableNames,
        tenantContext.tenantId,
        fetchConfig,
      ),
      getCachedConfig(
        "amfaConfigs",
        dynamodb,
        tenantContext.tableNames,
        tenantContext.tenantId,
        fetchConfig,
      ),
    ];

    const [amfaBrandings, amfaPolicies, amfaConfigs] =
      await Promise.all(configPromises);

    logger.debug("Configurations loaded", {
      requestId,
      tenantId: tenantContext.tenantId,
      configsLoaded: {
        brandings: Boolean(amfaBrandings),
        policies: Boolean(amfaPolicies),
        configs: Boolean(amfaConfigs),
      },
    });

    // Handle admin operations
    if (payload.phase.startsWith("admin")) {
      return await handleAdminOperations(
        payload,
        amfaConfigs,
        amfaPolicies,
        amfaBrandings,
        client,
        dynamodb,
        tenantContext,
        requestId,
      );
    }

    // Handle special operations
    if (["registotp", "removeProfile"].includes(payload.phase)) {
      return await handleSpecialOperations(
        payload,
        amfaConfigs,
        amfaBrandings,
        client,
        dynamodb,
        tenantContext,
        requestId,
      );
    }

    // Sanitize and format input data
    payload.uIP = getIPFromHeader(event.headers["X-Forwarded-For"]);
    payload.email = payload.email?.trim()?.toLowerCase();
    payload.origin = `${tenantContext.tenantId}.idapersona.${tenantContext.domainName}`;
    payload.otptype = payload.otptype?.toLowerCase();
    payload.requestTimeEpoch = event.requestContext.requestTimeEpoch;
    payload.newProfile = payload.newProfile
      ? payload.newProfile.toLowerCase()
      : "";
    payload.profile = payload.profile ? payload.profile.toLowerCase() : "";
    payload.cookies = event.headers["Cookie"];

    logger.debug("Payload sanitized", {
      requestId,
      tenantId: tenantContext.tenantId,
      sanitizedPayload: {
        phase: payload.phase,
        email: payload.email,
        uIP: payload.uIP,
        origin: payload.origin,
      },
    });

    // Handle username phase with user lookup
    if (payload.phase === "username") {
      return await handleUsernamePhase(
        payload,
        client,
        tenantContext,
        amfaBrandings,
        amfaPolicies,
        amfaConfigs,
        dynamodb,
        requestId,
      );
    }

    // Handle all other phases
    const headers = getHeaders(
      tenantContext.tenantId,
      tenantContext.domainName,
    );
    const stepResponse = await amfaSteps(
      payload,
      headers,
      client,
      payload.phase,
      amfaBrandings,
      amfaPolicies,
      amfaConfigs,
      dynamodb,
      tenantContext.tableNames,
      tenantContext.tenantId,
      tenantContext.userPoolId,
      tenantContext.domainName,
      tenantContext.appClientId,
      tenantContext.appSecret,
      tenantContext.magicString,
    );

    const duration = Date.now() - startTime;
    logger.info("Lambda execution completed successfully", {
      requestId,
      tenantId: tenantContext.tenantId,
      phase: payload.phase,
      duration,
      statusCode: stepResponse.statusCode,
    });

    return stepResponse;
  } catch (error) {
    const duration = Date.now() - startTime;
    logger.error("Lambda execution failed", error, {
      requestId,
      tenantId: tenantContext?.tenantId,
      duration,
      errorType: error.constructor.name,
    });

    return createErrorResponse(
      error.statusCode || 500,
      error.message || "Internal server error",
      requestId,
      tenantContext?.tenantId,
      tenantContext?.domainName,
    );
  }
};

// Helper function for admin operations
const handleAdminOperations = async (
  payload,
  amfaConfigs,
  amfaPolicies,
  amfaBrandings,
  client,
  dynamodb,
  tenantContext,
  requestId,
) => {
  const context = {
    requestId,
    tenantId: tenantContext.tenantId,
    phase: payload.phase,
  };

  try {
    switch (payload.phase) {
      case "adminchecklicense":
        if (amfaConfigs.asmurl && amfaPolicies["default"]) {
          logger.info("Checking license", {
            ...context,
            asmurl: amfaConfigs.asmurl,
          });
          const checkRes = await fetch(
            `${amfaConfigs.asmurl}/checkLic.kv?l=${amfaPolicies["default"].policy_name}&u=${payload.email}`,
            {
              method: "POST",
            },
          );

          let data = {};
          try {
            data = await checkRes.json();
          } catch (err) {
            logger.error("License check response parsing failed", err, context);
          }

          return responseWithRequestId(data?.code || 500, "OK", requestId, tenantContext.tenantId, tenantContext.domainName);
        } else {
          logger.error("Missing ASM URL or default policy", null, context);
          return responseWithRequestId(422, "Configuration error", requestId, tenantContext.tenantId, tenantContext.domainName);
        }

      case "admindeletetotp":
        const provider_id = await getProviderId(tenantContext.tenantId);
        const headers = getHeaders(
          tenantContext.tenantId,
          tenantContext.domainName,
        );
        return await deleteTotp(
          headers,
          payload.email,
          amfaConfigs,
          requestId,
          client,
          true,
          dynamodb,
          amfaBrandings.email_logo_url,
          amfaBrandings.service_name,
          true,
          provider_id,
        );

      case "admindeleteuser":
        logger.info("Admin delete user operation", context);
        const providerId = await getProviderId(tenantContext.tenantId);
        const deleteUserHeaders = getHeaders(
          tenantContext.tenantId,
          tenantContext.domainName,
        );
        const results = await Promise.allSettled([
          asmDeleteUser(
            deleteUserHeaders,
            payload.email,
            amfaConfigs,
            requestId,
            amfaPolicies,
            payload.admin,
          ),
          deleteTotp(
            deleteUserHeaders,
            payload.email,
            amfaConfigs,
            requestId,
            client,
            false,
            dynamodb,
            amfaBrandings.email_logo_url,
            amfaBrandings.service_name,
            true,
            providerId,
          ),
          deletePwdHashByUser(
            payload.email,
            dynamodb,
            amfaConfigs,
            tenantContext.tableNames,
            tenantContext.tenantId,
          ),
        ]);

        logger.info("Admin delete user completed", {
          ...context,
          results: results.map((r) => r.status),
        });
        return responseWithRequestId(200, "OK", requestId, tenantContext.tenantId, tenantContext.domainName);

      case "adminupdateuser":
        logger.info("Admin update user operation", context);
        await notifyProfileChange(tenantContext.tenantId, 
          payload.email,
          payload.otptype,
          payload.newProfileValue,
          amfaBrandings.email_logo_url,
          amfaBrandings.service_name,
          true,
        );
        return responseWithRequestId(200, "OK", requestId, tenantContext.tenantId, tenantContext.domainName);

      case "adminupdatesmtp":
        logger.info("Admin update SMTP operation", context);
        const updateSmtpResult = await adminSetSmtp(payload);
        return responseWithRequestId(
          updateSmtpResult ? 200 : 404,
          updateSmtpResult ? "OK" : payload.tenantid,
          requestId,
          tenantContext.tenantId,
          tenantContext.domainName,
        );

      case "admingetsecretinfo":
        logger.info("Admin get secrets operation", context);
        const result = await adminGetSecrets(payload.tenantid);
        return responseWithRequestId(
          result ? 200 : 404,
          result || payload.tenantid,
          requestId,
          tenantContext.tenantId,
          tenantContext.domainName,
        );

      default:
        logger.warn("Unknown admin operation", context);
        return responseWithRequestId(400, "Unknown admin operation", requestId, tenantContext.tenantId, tenantContext.domainName);
    }
  } catch (error) {
    logger.error("Admin operation failed", error, context);
    return responseWithRequestId(500, "Admin operation failed", requestId, tenantContext.tenantId, tenantContext.domainName);
  }
};

// Helper function for special operations
const handleSpecialOperations = async (
  payload,
  amfaConfigs,
  amfaBrandings,
  client,
  dynamodb,
  tenantContext,
  requestId,
) => {
  const context = {
    requestId,
    tenantId: tenantContext.tenantId,
    phase: payload.phase,
  };

  try {
    if (payload.phase === "registotp") {
      const isValidUuid = await checkSessionId(
        payload,
        payload.uuid,
        dynamodb,
        tenantContext.tableNames,
        tenantContext.tenantId,
      );
      if (isValidUuid) {
        const provider_id = await getProviderId(tenantContext.tenantId);
        const registotpHeaders = getHeaders(
          tenantContext.tenantId,
          tenantContext.domainName,
        );
        return await registotp(
          registotpHeaders,
          payload,
          amfaConfigs,
          requestId,
          amfaBrandings.email_logo_url,
          amfaBrandings.service_name,
          provider_id,
          client,
          dynamodb,
        );
      }
      logger.warn("Invalid UUID for registotp", context);
      return responseWithRequestId(400, "Invalid session", requestId, tenantContext.tenantId, tenantContext.domainName);
    }

    if (payload.phase === "removeProfile" && payload.otptype === "t") {
      const isValidUuid = await checkSessionId(
        payload,
        payload.uuid,
        dynamodb,
        tenantContext.tableNames,
        tenantContext.tenantId,
      );
      if (isValidUuid) {
        const provider_id = await getProviderId(tenantContext.tenantId);
        const removeProfileHeaders = getHeaders(
          tenantContext.tenantId,
          tenantContext.domainName,
        );
        return await deleteTotp(
          removeProfileHeaders,
          payload.email,
          amfaConfigs,
          requestId,
          client,
          true,
          dynamodb,
          amfaBrandings.email_logo_url,
          amfaBrandings.service_name,
          false,
          provider_id,
        );
      }
      logger.warn("Invalid UUID for removeProfile", context);
      return responseWithRequestId(400, "Invalid session", requestId, tenantContext.tenantId, tenantContext.domainName);
    }

    return responseWithRequestId(400, "Invalid special operation", requestId, tenantContext.tenantId, tenantContext.domainName);
  } catch (error) {
    logger.error("Special operation failed", error, context);
    return responseWithRequestId(500, "Special operation failed", requestId, tenantContext.tenantId, tenantContext.domainName);
  }
};

// Helper function for username phase
const handleUsernamePhase = async (
  payload,
  client,
  tenantContext,
  amfaBrandings,
  amfaPolicies,
  amfaConfigs,
  dynamodb,
  requestId,
) => {
  const context = {
    requestId,
    tenantId: tenantContext.tenantId,
    phase: "username",
    email: payload.email,
  };

  try {
    const res = await client.send(
      new ListUsersCommand({
        UserPoolId: tenantContext.userPoolId,
        Filter: `email = "${payload.email}"`,
      }),
    );

    logger.debug("User lookup completed", {
      ...context,
      userCount: res.Users?.length || 0,
    });

    if (res && res.Users && res.Users.length > 0) {
      const usernameHeaders = getHeaders(
        tenantContext.tenantId,
        tenantContext.domainName,
      );
      const stepOneResponse = await amfaSteps(
        payload,
        usernameHeaders,
        client,
        payload.phase,
        amfaBrandings,
        amfaPolicies,
        amfaConfigs,
        dynamodb,
        tenantContext.tableNames,
        tenantContext.tenantId,
        tenantContext.userPoolId,
        tenantContext.domainName,
      );

      logger.info("Username phase completed successfully", {
        ...context,
        statusCode: stepOneResponse.statusCode,
      });

      return stepOneResponse;
    } else {
      // User not found - return generic response to prevent username enumeration
      logger.info("User not found - preventing enumeration", context);
      return responseWithRequestId(
        202,
        "Your identity requires password login.",
        requestId,
        tenantContext.tenantId,
        tenantContext.domainName,
      );
    }
  } catch (error) {
    logger.error("Username phase failed", error, context);
    return responseWithRequestId(500, "User lookup failed", requestId, tenantContext.tenantId, tenantContext.domainName);
  }
};
