// ASM (Adaptive Security Manager) integration utilities for AMFA steps
import { createHash } from "node:crypto";
import { getTType } from "../amfaUtils.mjs";
import { validateTotp } from "../totp/verifyOtp.mjs";
import { logger } from "./logger.mjs";

const hash = (content) => createHash("md5").update(content).digest("hex");

// Helper function to execute ASM authentication
export const executeASMAuthentication = async (
  event,
  step,
  asmurl,
  policyName,
  salt,
  tenantId,
  domainName,
  amfaConfigs,
  context,
  dynamodb
) => {
  try {
    const l = encodeURI(policyName);
    const wr = event.origin;
    const sfl = 6;
    const u = encodeURIComponent(event.email);
    const igd = event.rememberDevice === "true" ? 0 : 1;
    const a = encodeURI(event.authParam);
    const uIp = event.uIP || "0.0.0.0";
    const apti = event.apti;
    const otpm = event.otptype || "e";
    const p = encodeURIComponent(event.otpaddr || event.email);
    let otpp = 1;
    let nsf = event.rememberDevice ? 0 : 1;
    const af1 = u + "passwordless_check" + uIp;

    const amfaCookieName = hash(`${u}${policyName}${wr}${salt}`);
    let c = "";

    if (event.cookies && event.cookies.trim().length > 0) {
      const startingIdx = event.cookies.trim().indexOf(amfaCookieName);
      if (startingIdx > -1) {
        const startIndex = startingIdx + amfaCookieName.length + 1;
        c = event.cookies.trim().substring(startIndex).split(";")[0];
      }
    }

    let postURL = "";
    const tType = getTType(step);

    // Build URL based on step
    switch (step) {
      case "username":
        nsf = event.rememberDevice ? 0 : 3;
        postURL = `${asmurl}/extAuthenticate.kv?l=${l}&u=${u}&uIp=${uIp}&apti=${apti}&c=${c}&wr=${wr}&otpm=${otpm}&p=${p}&otpp=${otpp}&af1=${af1}&a=${a}&igd=${igd}&nsf=${nsf}&tType=${tType}&sfl=${sfl}&bypassthreat=1`;
        break;

      case "password":
        postURL = `${asmurl}/extAuthenticate.kv?l=${l}&u=${u}&uIp=${uIp}&apti=${apti}&c=${c}&wr=${wr}&otpm=${otpm}&p=${p}&otpp=${otpp}&af1=${af1}&a=${a}&igd=${igd}&nsf=${nsf}&tType=${tType}`;
        break;

      case "sendotp":
        if (event.otptype === "t") {
          return { code: 202, message: "Awaiting Mobile TOTP code" };
        }
        postURL = `${asmurl}/extResendOtp.kv?l=${l}&u=${u}&apti=${apti}&uIp=${uIp}&otpm=${otpm}&p=${p}&tType=${tType}`;
        break;

      case "verifyotp":
      case "pwdresetverify2":
      case "pwdresetverify3":
      case "selfserviceverify2":
      case "selfserviceverify3":
      case "updateProfile":
      case "emailverificationverifyotp":
        if (event.otptype === "t") {
          await validateTotp({ email: event.email }, dynamodb);
        }
        const o = event.otpcode;
        postURL = `${asmurl}/extVerifyOtp.kv?l=${l}&u=${u}&uIp=${uIp}&c=${c}&apti=${apti}&wr=${wr}&igd=${igd}&nsf=${nsf}&otpm=${otpm}&p=${p}&otpp=${otpp}&tType=${tType}&o=${o}&af1=${af1}&a=${a}`;
        break;

      case "pwdreset2":
      case "pwdreset3":
      case "selfservice2":
      case "selfservice3":
      case "updateProfileSendOTP":
      case "emailverificationSendOTP":
        if (event.isResend) {
          postURL = `${asmurl}/extResendOtp.kv?l=${l}&u=${u}&apti=${apti}&uIp=${uIp}&otpm=${otpm}&p=${p}&tType=${tType}`;
        } else {
          otpp = event.otptype === "t" ? 1 : 0;
          const sflOverride = 7;
          postURL = `${asmurl}/extAuthenticate.kv?l=${l}&sfl=${sflOverride}&u=${u}&apti=${apti}&uIp=${uIp}&otpm=${otpm}&p=${p}&tType=${tType}&otpp=${otpp}&nsf=${nsf}&igd=${igd}&a=${a}`;
        }
        break;

      default:
        logger.warn("Unknown step for ASM URL building", { ...context, step });
        return null;
    }

    logger.debug("Executing ASM request", {
      ...context,
      url: postURL.replace(/&[^&]*password[^&]*=[^&]*/gi, "&password=***"),
    });

    const amfaResponse = await fetch(postURL, { method: "POST" });

    if (amfaResponse && amfaResponse.status) {
      const amfaResponseJSON = await amfaResponse.json();
      logger.debug("ASM response received", {
        ...context,
        code: amfaResponseJSON.code,
        message: amfaResponseJSON.message,
      });
      return amfaResponseJSON;
    }

    return null;
  } catch (error) {
    logger.error("ASM authentication failed", error, context);
    return null;
  }
};

// Helper function to build cookie name for ASM
export const buildCookieName = (email, policyName, origin, salt) => {
  return hash(`${encodeURIComponent(email)}${policyName}${origin}${salt}`);
};
