// Enhanced logging utility for AMFA steps
export const logger = {
  info: (message, context = {}) => {
    console.log(
      JSON.stringify({
        level: "INFO",
        timestamp: new Date().toISOString(),
        message,
        ...context,
      })
    );
  },
  warn: (message, context = {}) => {
    console.warn(
      JSON.stringify({
        level: "WARN",
        timestamp: new Date().toISOString(),
        message,
        ...context,
      })
    );
  },
  error: (message, error = null, context = {}) => {
    console.error(
      JSON.stringify({
        level: "ERROR",
        timestamp: new Date().toISOString(),
        message,
        error: error
          ? {
              name: error.name,
              message: error.message,
              stack: error.stack,
            }
          : null,
        ...context,
      })
    );
  },
  debug: (message, context = {}) => {
    if (process.env.LOG_LEVEL === "DEBUG") {
      console.log(
        JSON.stringify({
          level: "DEBUG",
          timestamp: new Date().toISOString(),
          message,
          ...context,
        })
      );
    }
  },
};
