// User management utilities for AMFA steps
import {
  AdminListGroupsForUserCommand,
  ListUsersCommand,
} from "@aws-sdk/client-cognito-identity-provider";
import { getTotp } from "../totp/getToken.mjs";
import { logger } from "./logger.mjs";

// Cache for frequently accessed data within the same execution
const executionCache = new Map();

// Clear cache at the start of each request
export const clearUserCache = () => {
  executionCache.clear();
};

// Optimized user attribute transformation with caching
export const transUAttr = async (
  email,
  userAttributes,
  allowed_otp_methods,
  asm_provider_id,
  dynamodb,
  totpTokenTable
) => {
  const cacheKey = `transUAttr_${email}_${JSON.stringify(allowed_otp_methods)}`;

  if (executionCache.has(cacheKey)) {
    logger.debug("Using cached user attributes transformation", {
      email,
      cacheKey,
    });
    return executionCache.get(cacheKey);
  }

  try {
    const phoneNumber = userAttributes.phone_number
      ? userAttributes.phone_number.replace(/(\d{3})(\d{5})(\d{1})/, "$1xxx$3")
      : null;

    let aemail = userAttributes["custom:alter-email"]
      ? userAttributes["custom:alter-email"]
      : null;
    if (aemail && aemail.indexOf("@") > 0) {
      aemail = `${aemail[0]}xxx@${
        aemail[aemail.lastIndexOf("@") + 1]
      }xx.${aemail.substring(aemail.lastIndexOf(".") + 1)}`;
    } else {
      aemail = null;
    }

    const vPhoneNumber = userAttributes["custom:voice-number"]
      ? userAttributes["custom:voice-number"].replace(
          /(\d{3})(\d{5})(\d{1})/,
          "$1xxx$3"
        )
      : null;

    const mobileToken = await getTotp(email, asm_provider_id, dynamodb, totpTokenTable);

    let tempOtpData = { phoneNumber, aemail, vPhoneNumber, mobileToken };
    let otpData = {
      aemail: null,
      phoneNumber: null,
      vPhoneNumber: null,
      mobileToken: null,
    };

    if (allowed_otp_methods) {
      allowed_otp_methods.forEach((method) => {
        switch (method) {
          case "ae":
            otpData.aemail = tempOtpData.aemail;
            break;
          case "s":
            otpData.phoneNumber = tempOtpData.phoneNumber;
            break;
          case "v":
            otpData.vPhoneNumber = tempOtpData.vPhoneNumber;
            break;
          case "t":
            otpData.mobileToken = mobileToken;
            break;
          default:
            break;
        }
      });
    } else {
      otpData = tempOtpData;
    }

    // Cache the result for this execution
    executionCache.set(cacheKey, otpData);

    return otpData;
  } catch (error) {
    logger.error("Error in transUAttr", error, { email, allowed_otp_methods });
    return {
      aemail: null,
      phoneNumber: null,
      vPhoneNumber: null,
      mobileToken: null,
    };
  }
};

// Optimized user lookup with caching
export const getUserInfo = async (email, cognito, userPoolId, tenantId) => {
  const cacheKey = `user_${email}_${userPoolId}`;

  if (executionCache.has(cacheKey)) {
    logger.debug("Using cached user info", { email, tenantId });
    return executionCache.get(cacheKey);
  }

  try {
    const listUsersParam = {
      UserPoolId: userPoolId,
      Filter: `email = "${email}"`,
    };

    const listUsersRes = await cognito.send(
      new ListUsersCommand(listUsersParam)
    );
    logger.debug("User lookup completed", {
      email,
      tenantId,
      userCount: listUsersRes.Users?.length || 0,
    });

    if (
      !listUsersRes ||
      !listUsersRes.Users ||
      listUsersRes.Users.length === 0
    ) {
      const result = {
        user: null,
        userAttributes: null,
        error: "User not found",
      };
      executionCache.set(cacheKey, result);
      return result;
    }

    const users = listUsersRes.Users.filter((user) => {
      return (
        user.UserStatus === "CONFIRMED" ||
        user.UserStatus === "FORCE_CHANGE_PASSWORD"
      );
    });

    if (users.length === 0) {
      const result = {
        user: null,
        userAttributes: null,
        error: "No confirmed users found",
      };
      executionCache.set(cacheKey, result);
      return result;
    }

    const user = users[0];
    const userAttributes = user.Attributes.reduce((acc, curr) => {
      acc[curr.Name] = curr.Value;
      return acc;
    }, {});

    const result = { user, userAttributes, error: null };
    executionCache.set(cacheKey, result);

    return result;
  } catch (error) {
    logger.error("Error in getUserInfo", error, { email, tenantId });
    const result = { user: null, userAttributes: null, error: error.message };
    executionCache.set(cacheKey, result);
    return result;
  }
};

// Optimized user group lookup with caching
export const getUserGroup = async (
  username,
  cognito,
  userPoolId,
  amfaPolicies,
  tenantId
) => {
  const cacheKey = `usergroup_${username}_${userPoolId}`;

  if (executionCache.has(cacheKey)) {
    logger.debug("Using cached user group", { username, tenantId });
    return executionCache.get(cacheKey);
  }

  try {
    const param = {
      UserPoolId: userPoolId,
      Username: username,
    };

    const userGroup = await cognito.send(
      new AdminListGroupsForUserCommand(param)
    );
    logger.debug("User group lookup completed", {
      username,
      tenantId,
      groupCount: userGroup.Groups?.length || 0,
    });

    let ug = "default";
    let ugRank = 10000;

    for (let i = 0; i < userGroup.Groups.length; i++) {
      const groupName = userGroup.Groups[i].GroupName.toLowerCase();
      if (amfaPolicies[groupName] && amfaPolicies[groupName].rank < ugRank) {
        ug = groupName;
        ugRank = amfaPolicies[groupName].rank;
      }
    }

    if (!amfaPolicies[ug]) {
      ug = "default";
    }

    executionCache.set(cacheKey, ug);
    return ug;
  } catch (error) {
    logger.error("Error in getUserGroup", error, { username, tenantId });
    executionCache.set(cacheKey, "default");
    return "default";
  }
};

// Helper function to validate OTP address
export const validateOTPAddress = async (event, userAttributes, context) => {
  logger.debug("Validating OTP address", {
    ...context,
    otptype: event.otptype,
  });

  switch (event.otptype) {
    case "e":
      return (
        event.otpaddr.toLowerCase().trim() ===
        userAttributes["email"]?.toLowerCase().trim()
      );
    case "ae":
      return (
        event.otpaddr.toLowerCase().trim() ===
        userAttributes["custom:alter-email"]?.toLowerCase().trim()
      );
    case "s":
      return event.otpaddr.trim() === userAttributes?.phone_number?.trim();
    case "v":
      const value =
        userAttributes["custom:voice-number"] || userAttributes.phone_number;
      return event.otpaddr.trim() === value?.trim();
    default:
      return false;
  }
};

// Helper function to set OTP address
// BUG FIX: When user is registering a NEW profile (event.newProfile is set),
// the OTP should be sent to the NEW address, not the old one from Cognito.
// Previously, for first-time alt-email/phone setup, userAttributes["custom:alter-email"]
// was undefined → fallback to event.email → OTP sent to primary email instead.
export const setOTPAddress = async (event, userAttributes) => {
  switch (event.otptype) {
    case "e":
      event.otpaddr = event.email;
      break;
    case "ae":
      // For profile update: send OTP to the NEW alt-email being registered
      event.otpaddr = event.newProfile || userAttributes["custom:alter-email"];
      break;
    case "s":
      // For profile update: send OTP to the NEW phone number being registered
      event.otpaddr = event.newProfile || userAttributes?.phone_number;
      break;
    case "v":
      // For profile update: send OTP to the NEW voice number being registered
      event.otpaddr = event.newProfile ||
        userAttributes["custom:voice-number"] || userAttributes.phone_number;
      break;
    default:
      break;
  }
  event.otpaddr = event.otpaddr?.toLowerCase();
};

// Utility functions
export const intersectOtpPolicies = (
  usergroupPolicies,
  amfaConfigsMasterPolicies
) =>
  amfaConfigsMasterPolicies
    ? usergroupPolicies.filter((policy) =>
        amfaConfigsMasterPolicies.includes(policy)
      )
    : usergroupPolicies;
