import {
	GetItemCommand,
} from '@aws-sdk/client-dynamodb';

export const fetchConfig = async (configType, dynamodb, tableNames, tenantId) => {
    // Use tenant-specific config table name
    const tableName = tableNames.amfaConfigTable;
    
    const params = {
      TableName: tableName,
      Key: {
        id: {S: tenantId},
        configtype: {S: configType},
      },
    };
	const getItemCommand = new GetItemCommand(params);
	const results = await dynamodb.send(getItemCommand);

	if (results.Item === undefined) {
		throw new Error(`[Tenant: ${tenantId || 'unknown'}] No ${configType} found for tenant ${tenantId} in table ${tableName}`);
	}

	const result = JSON.parse(results.Item.value.S);

	console.log(`[Tenant: ${tenantId || 'unknown'}] get ${configType}:`, result);
	return result;

}
